<script>
export default {
  name: "netWorkStatus", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      deviceReady: false,
    };
  },
  computed: {},
  created() {},
  mounted() {
    this.onLoad();
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //标识cordova环境是否准备好,初始值为false

    //页面加载时执行
    onLoad() {
      document.addEventListener("deviceready", this.onDeviceReady, false);
    },

    onDeviceReady() {
      console.log("onDeviceReady()--->start()");
      this.deviceReady = true;
      //添加监听器[监听网络连上]
      document.addEventListener("online", this.onOnLine, false);

      //添加监听器[监听网络断开]
      document.addEventListener("offline", this.onOffLine, false);

      console.log("onDeviceReady()--->end()");
    },

    //获取网络状态
    getNetWorkStatus() {
      console.log("getNetWorkStatus(),this.deviceReady:" + this.deviceReady);
      if (!this.deviceReady) {
        return;
      }

      var networkState = mam.navigator.connection.type;
      var states = {};
      var retStates = "";
      states[Connection.UNKNOWN] = "Unknown connection";
      states[Connection.ETHERNET] = "Ethernet connection";
      states[Connection.WIFI] = "WiFi connection";
      states[Connection.CELL_2G] = "Cell 2G connection";
      states[Connection.CELL_3G] = "Cell 3G connection";
      states[Connection.CELL_4G] = "Cell 4G connection";
      states[Connection.CELL] = "Cell generic connection";
      states[Connection.NONE] = "No network connection";
      console.log(
        "getNetWorkStatus(),states[networkState]:" + states[networkState]
      );
      retStates = states[networkState];
      return retStates;
    },

    //显示网络状态
    showNetWorkStatus() {
      var status = this.getNetWorkStatus();
      document.getElementById("divGetNetWorkStatus").innerHTML = status;
    },

    //清除网络状态
    clearNetWorkStatus() {
      document.getElementById("divGetNetWorkStatus").innerHTML = "";
    },

    //网络连上时调用
    onOnLine() {
      var result = "";
      result = "网络连上..." + "<br/>" + this.getNetWorkStatus();
      document.getElementById("divListenerNetWorkStatus").innerHTML = result;
    },

    //网络断开时调用
    onOffLine() {
      document.getElementById("divListenerNetWorkStatus").innerHTML =
        "网络断开...";
    },
    requireImg(url) {
      return require("@/assets/" + url);
    },
  },
};
</script>
